orize: definitionsToAuthorizeWrapper,\n        },\n      },\n      spec: {\n        selectors: {\n          isOAS31: createSystemSelector(selectIsOAS31),\n\n          license: selectLicense,\n          selectLicenseNameField,\n          selectLicenseUrlField,\n          selectLicenseIdentifierField: createOnlyOAS31Selector(selectLicenseIdentifierField), // prettier-ignore\n          selectLicenseUrl: createSystemSelector(selectLicenseUrl),\n\n          contact: selectContact,\n          selectContactNameField,\n          selectContactEmailField,\n          selectContactUrlField,\n          selectContactUrl: createSystemSelector(selectContactUrl),\n\n          selectInfoTitleField,\n          selectInfoSummaryField: createOnlyOAS31Selector(selectInfoSummaryField), // prettier-ignore\n          selectInfoDescriptionField,\n          selectInfoTermsOfServiceField,\n          selectInfoTermsOfServiceUrl: createSystemSelector(selectInfoTermsOfServiceUrl), // prettier-ignore\n\n          selectExternalDocsDescriptionField,\n          selectExternalDocsUrlField,\n          selectExternalDocsUrl: createSystemSelector(selectExternalDocsUrl),\n\n          webhooks: createOnlyOAS31Selector(selectWebhooks),\n          selectWebhooksOperations: createOnlyOAS31Selector(createSystemSelector(selectWebhooksOperations)), // prettier-ignore\n\n          selectJsonSchemaDialectField,\n          selectJsonSchemaDialectDefault,\n\n          selectSchemas: createSystemSelector(selectSchemas),\n        },\n        wrapSelectors: {\n          isOAS3: isOAS3SelectorWrapper,\n          selectLicenseUrl: selectLicenseUrlWrapper,\n        },\n      },\n      oas31: {\n        selectors: {\n          selectLicenseUrl: createOnlyOAS31Selector(createSystemSelector(selectOAS31LicenseUrl)), // prettier-ignore\n        },\n      },\n    },\n  }\n}\n\nexport default OAS31Plugin\n","/**\n * @prettier\n */\nimport PropTypes from \"prop-types\"\n\nexport const objectSchema = PropTypes.object\n\nexport const booleanSchema = PropTypes.bool\n\nexport const schema = PropTypes.oneOfType([objectSchema, booleanSchema])\n","/**\n * @prettier\n */\nimport { createContext } from \"react\"\n\nexport const JSONSchemaContext = createContext(null)\nJSONSchemaContext.displayName = \"JSONSchemaContext\"\n\nexport const JSONSchemaLevelContext = createContext(0)\nJSONSchemaLevelContext.displayName = \"JSONSchemaLevelContext\"\n\nexport const JSONSchemaCyclesContext = createContext(new Set())\n\nexport const JSONSchemaPathContext = createContext([])\n","/**\n * @prettier\n */\nexport class JSONSchemaIsExpandedState {\n  static Collapsed = \"collapsed\"\n\n  static Expanded = \"expanded\"\n\n  static DeeplyExpanded = \"deeply-expanded\"\n}\n","/**\n * @prettier\n */\nimport { useCallback, useContext, useEffect, useState } from \"react\"\n\nimport {\n  JSONSchemaContext,\n  JSONSchemaLevelContext,\n  JSONSchemaCyclesContext,\n  JSONSchemaPathContext,\n} from \"./context\"\nimport { JSONSchemaIsExpandedState } from \"./enum\"\n\nexport const useConfig = () => {\n  const { config } = useContext(JSONSchemaContext)\n  return config\n}\n\nexport const useComponent = (componentName) => {\n  const { components } = useContext(JSONSchemaContext)\n  return components[componentName] || null\n}\n\nexport const useFn = (fnName = undefined) => {\n  const { fn } = useContext(JSONSchemaContext)\n\n  return typeof fnName !== \"undefined\" ? fn[fnName] : fn\n}\n\nexport const useJSONSchemaContextState = () => {\n  const [, setFakeState] = useState(null)\n  const { state } = useContext(JSONSchemaContext)\n  const setState = (updateFn) => {\n    updateFn(state)\n    setFakeState({})\n  }\n\n  return { state, setState }\n}\n\nexport const useLevel = () => {\n  const level = useContext(JSONSchemaLevelContext)\n\n  return [level, level + 1]\n}\n\nexport const useIsEmbedded = () => {\n  const [level] = useLevel()\n\n  return level > 0\n}\n\nexport const usePath = (pathToken) => {\n  const path = useContext(JSONSchemaPathContext)\n  const { setState } = useJSONSchemaContextState()\n  const currentPath =\n    typeof pathToken === \"string\" ? [...path, pathToken] : path\n\n  const pathMutator = (value, options = { deep: false }) => {\n    const startPath = currentPath.toString()\n    const updateFn = (state) => {\n      state.paths[startPath] = value\n\n      if (value === JSONSchemaIsExpandedState.Collapsed) {\n        Object.keys(state.paths).forEach((key) => {\n          if (\n            key.startsWith(startPath) &&\n            state.paths[key] === JSONSchemaIsExpandedState.DeeplyExpanded\n          ) {\n            state.paths[key] = JSONSchemaIsExpandedState.Expanded\n          }\n        })\n      }\n    }\n    const updateDeepFn = (state) => {\n      Object.keys(state.paths).forEach((key) => {\n        if (key.startsWith(startPath)) {\n          state.paths[key] = value\n        }\n      })\n    }\n\n    if (options.deep) {\n      setState(updateDeepFn)\n    } else {\n      setState(updateFn)\n    }\n  }\n\n  return { path: currentPath, pathMutator }\n}\n\nexport const useIsExpanded = (name) => {\n  const [level] = useLevel()\n  const { defaultExpandedLevels } = useConfig()\n  const { path, pathMutator } = usePath(name)\n  const { path: parentPath } = usePath()\n  const { state } = useJSONSchemaContextState()\n  const currentState = state.paths[path.toString()]\n  const parentState =\n    state.paths[parentPath.toString()] ??\n    state.paths[parentPath.slice(0, -1).toString()]\n  const isExpandedState =\n    currentState ??\n    (defaultExpandedLevels - level > 0\n      ? JSONSchemaIsExpandedState.Expanded\n      : JSONSchemaIsExpandedState.Collapsed)\n  const isExpanded = isExpandedState !== JSONSchemaIsExpandedState.Collapsed\n\n  useEffect(() => {\n    pathMutator(\n      parentState === JSONSchemaIsExpandedState.DeeplyExpanded\n        ? JSONSchemaIsExpandedState.DeeplyExpanded\n        : isExpandedState\n    )\n  }, [parentState])\n\n  const setExpanded = useCallback((options = { deep: false }) => {\n    pathMutator(\n      options.deep\n        ? JSONSchemaIsExpandedState.DeeplyExpanded\n        : JSONSchemaIsExpandedState.Expanded\n    )\n  }, [])\n\n  const setCollapsed = useCallback((options = { deep: false }) => {\n    pathMutator(JSONSchemaIsExpandedState.Collapsed, options)\n  }, [])\n\n  return { isExpanded, setExpanded, setCollapsed }\n}\n\nexport const useRenderedSchemas = (schema = undefined) => {\n  if (typeof schema === \"undefined\") {\n    return useContext(JSONSchemaCyclesContext)\n  }\n\n  const renderedSchemas = useContext(JSONSchemaCyclesContext)\n  return new Set([...renderedSchemas, schema])\n}\nexport const useIsCircular = (schema) => {\n  const renderedSchemas = useRenderedSchemas()\n  return renderedSchemas.has(schema)\n}\n","/**\n * @prettier\n */\nimport React, { forwardRef, useCallback } from \"react\"\nimport PropTypes from \"prop-types\"\nimport classNames from \"classnames\"\n\nimport * as propTypes from \"../../prop-types\"\nimport {\n  useComponent,\n  useLevel,\n  useFn,\n  useIsEmbedded,\n  useIsExpanded,\n  useIsCircular,\n  useRenderedSchemas,\n  usePath,\n} from \"../../hooks\"\nimport {\n  JSONSchemaLevelContext,\n  JSONSchemaCyclesContext,\n  JSONSchemaPathContext,\n} from \"../../context\"\n\nconst JSONSchema = forwardRef(\n  (\n    {\n      schema,\n      name = \"\",\n      dependentRequired = [],\n      onExpand = () => {},\n      identifier = \"\",\n    },\n    ref\n  ) => {\n    const fn = useFn()\n    // this implementation assumes that $id is always non-relative URI\n    const pathToken = identifier || schema?.$id || name\n    const { path } = usePath(pathToken)\n    const { isExpanded, setExpanded, setCollapsed } = useIsExpanded(pathToken)\n    const [level, nextLevel] = useLevel()\n    const isEmbedded = useIsEmbedded()\n    const isExpandable = fn.isExpandable(schema) || dependentRequired.length > 0\n    const isCircular = useIsCircular(schema)\n    const renderedSchemas = useRenderedSchemas(schema)\n    const constraints = fn.stringifyConstraints(schema)\n    const Accordion = useComponent(\"Accordion\")\n    const Keyword$schema = useComponent(\"Keyword$schema\")\n    const Keyword$vocabulary = useComponent(\"Keyword$vocabulary\")\n    const Keyword$id = useComponent(\"Keyword$id\")\n    const Keyword$anchor = useComponent(\"Keyword$anchor\")\n    const Keyword$dynamicAnchor = useComponent(\"Keyword$dynamicAnchor\")\n    const Keyword$ref = useComponent(\"Keyword$ref\")\n    const Keyword$dynamicRef = useComponent(\"Keyword$dynamicRef\")\n    const Keyword$defs = useComponent(\"Keyword$defs\")\n    const Keyword$comment = useComponent(\"Keyword$comment\")\n    const KeywordAllOf = useComponent(\"KeywordAllOf\")\n    const KeywordAnyOf = useComponent(\"KeywordAnyOf\")\n    const KeywordOneOf = useComponent(\"KeywordOneOf\")\n    const KeywordNot = useComponent(\"KeywordNot\")\n    const KeywordIf = useComponent(\"KeywordIf\")\n    const KeywordThen = useComponent(\"KeywordThen\")\n    const KeywordElse = useComponent(\"KeywordElse\")\n    const KeywordDependentSchemas = useComponent(\"KeywordDependentSchemas\")\n    const KeywordPrefixItems = useComponent(\"KeywordPrefixItems\")\n    const KeywordItems = useComponent(\"KeywordItems\")\n    const KeywordContains = useComponent(\"KeywordContains\")\n    const KeywordProperties = useComponent(\"KeywordProperties\")\n    const KeywordPatternProperties = useComponent(\"KeywordPatternProperties\")\n    const KeywordAdditionalProperties = useComponent(\n      \"KeywordAdditionalProperties\"\n    )\n    const KeywordPropertyNames = useComponent(\"KeywordPropertyNames\")\n    const KeywordUnevaluatedItems = useComponent(\"KeywordUnevaluatedItems\")\n    const KeywordUnevaluatedProperties = useComponent(\n      \"KeywordUnevaluatedProperties\"\n    )\n    const KeywordType = useComponent(\"KeywordType\")\n    const KeywordEnum = useComponent(\"KeywordEnum\")\n    const KeywordConst = useComponent(\"KeywordConst\")\n    const KeywordConstraint = useComponent(\"KeywordConstraint\")\n    const KeywordDependentRequired = useComponent(\"KeywordDependentRequired\")\n    const KeywordContentSchema = useComponent(\"KeywordContentSchema\")\n    const KeywordTitle = useComponent(\"KeywordTitle\")\n    const KeywordDescription = useComponent(\"KeywordDescription\")\n    const KeywordDefault = useComponent(\"KeywordDefault\")\n    const KeywordDeprecated = useComponent(\"KeywordDeprecated\")\n    const KeywordReadOnly = useComponent(\"KeywordReadOnly\")\n    const KeywordWriteOnly = useComponent(\"KeywordWriteOnly\")\n    const KeywordExamples = useComponent(\"KeywordExamples\")\n    const ExtensionKeywords = useComponent(\"ExtensionKeywords\")\n    const ExpandDeepButton = useComponent(\"ExpandDeepButton\")\n\n    /**\n     * Event handlers.\n     */\n    const handleExpansion = useCallback(\n      (e, expandedNew) => {\n        if (expandedNew) {\n          setExpanded()\n        } else {\n          setCollapsed()\n        }\n        onExpand(e, expandedNew, false)\n      },\n      [onExpand, setExpanded, setCollapsed]\n    )\n    const handleExpansionDeep = useCallback(\n      (e, expandedDeepNew) => {\n        if (expandedDeepNew) {\n          setExpanded({ deep: true })\n        } else {\n          setCollapsed({ deep: true })\n        }\n        onExpand(e, expandedDeepNew, true)\n      },\n      [onExpand, setExpanded, setCollapsed]\n    )\n\n    return (\n      <JSONSchemaPathContext.Provider value={path}>\n        <JSONSchemaLevelContext.Provider value={nextLevel}>\n          <JSONSchemaCyclesContext.Provider value={renderedSchemas}>\n            <article\n              ref={ref}\n              data-json-schema-level={level}\n              className={classNames(\"json-schema-2020-12\", {\n                \"json-schema-2020-12--embedded\": isEmbedded,\n                \"json-schema-2020-12--circular\": isCircular,\n              })}\n            >\n    